def remove_Occ(s, char):
    if not s or not char:
        return s

    start = -1
    end = -1

    # Find first occurrence
    for i, c in enumerate(s):
        if c == char:
            start = i
            break

    # Find last occurrence
    for i in range(len(s) - 1, -1, -1):
        if s[i] == char:
            end = i
            break

    if start == -1 or start == end:
        return s

    # Remove first and last occurrence
    if start == 0 and end == len(s) - 1:
        return s[1:-1]
    elif start == 0:
        return s[1:]
    elif end == len(s) - 1:
        return s[:-1]
    else:
        return s[:start] + s[start+1:end] + s[end+1:]

