def split_lowerstring(s):
    if not s:
        return []

    result = []
    start = 0

    for i in range(1, len(s)):
        if s[i].islower() and not s[i-1].islower():
            result.append(s[start:i])
            start = i

    # Append the last segment if it starts with a lowercase letter
    if s[start:].islower():
        result.append(s[start:])

    # Handle edge cases where the string starts with lowercase
    if s[0].islower():
        result = [s[0]] + result

    # Clean up empty strings that might result from consecutive lowercase letters
    final_result = []
    current = ""
    for char in result:
        if char:
            current += char
        else:
            if current:
                final_result.append(current)
                current = ""
    if current:
        final_result.append(current)

    return final_result

