def is_woodall(n):
    """
    Check if the number n is a Woodall number.
    A Woodall number is defined as n = k * 2^k - 1 for some integer k >= 1.
    """
    if n < 0:
        return False
    if n == 0:
        return False

    # We need to find if there exists an integer k such that k * 2^k - 1 = n
    # Since k * 2^k grows very fast, we can iterate k starting from 1
    k = 1
    while True:
        woodall_val = k * (2 ** k) - 1
        if woodall_val == n:
            return True
        if woodall_val > n:
            return False
        k += 1

