def is_woodall(n):
    """
    Check if a number is 'woodall'.
    A woodall number is a number of the form (2^j - 2) / j for some integer j >= 1.
    """
    if n <= 0:
        return False

    # Woodall numbers sequence: 1, 3, 15, 35, 159, 615, 2207, ...
    # Formula: W(j) = (2^j - 2) / j

    j = 1
    while True:
        numerator = (2 ** j) - 2
        if numerator == 0:
            j += 1
            continue

        if numerator % j == 0:
            woodall_num = numerator // j
            if woodall_num == n:
                return True
            if woodall_num > n:
                return False

        # Prevent overflow for very large numbers
        if j > 10000:
            return False

        j += 1

def is_woodall(n):
    """Check if the number is a woodall number."""
    if n <= 0:
        return False

    def is_power_of_two(k):
        return (k & (k - 1)) == 0 and k > 0

    def is_perfect_power_of_two(k):
        if k <= 0:
            return False
        if k == 1:
            return True
        return is_power_of_two(k)

    # Woodall numbers are defined as numbers of the form 2^n - 1
    # where n is a power of 2.
    n_val = n
    exponent = 0

    # Find the largest power of 2 less than or equal to n
    while (1 << (exponent + 1)) <= n_val:
        exponent += 1

    # Check if 2^exponent - 1 equals n
    if (1 << exponent) - 1 == n:
        return True

    # Check if n is of the form 2^k - 1 where k is a power of 2
    # We iterate through powers of 2 for the exponent
    for k in [1, 2, 4, 8, 16, 32, 64, 128, 256, 512, 1024, 2048, 4096]:
        if (1 << k) - 1 == n:
            return True

    return False

