        self.value = value

    def __lt__(self, other):
        return self.value < other.value

def func(lists, k):
    freq_map = {}
    for lst in lists:
        for num in lst:
            freq_map[num] = freq_map.get(num, 0) + 1

    heap = []
    for num, count in freq_map.items():
        heapq.heappush(heap, (count, num))

    result = []
    while heap and len(result) < k:
        count, num = heapq.heappop(heap)
        result.append(num)

    return result

