def func(lists, k):
    # Count frequencies of each integer
    count = {}
    for lst in lists:
        for num in lst:
            count[num] = count.get(num, 0) + 1

    # Use a min-heap to keep track of the top k elements
    heap = []
    for num, freq in count.items():
        if len(heap) < k:
