def find_rect_num(n):
    """
    Find the n-th rectangular number.
    A rectangular number is a number that can be represented as the product of two integers.
    The n-th rectangular number is the n-th number in the sorted sequence of all rectangular numbers.
    """
    def is_rectangular(num):
        for i in range(1, int(num**0.5) + 1):
            if num % i == 0:
                return True
        return False

    count = 0
    num = 1
    while count < n:
        if is_rectangular(num):
            count += 1
        num += 1
    return num - 1

