def find_Nth_Digit(numerator, denominator, n):
    if denominator == 0:
        raise ValueError("Denominator cannot be zero.")

    # Perform integer division to get the integer part
    integer_part = numerator // denominator
    remainder = numerator % denominator

    # If n is within the integer part, return the nth digit of the integer part
    if n <= len(str(integer_part)):
        return int(str(integer_part)[n-1])

    # Generate the decimal part
    decimal_digits = []
    for _ in range(n - len(str(integer_part))):
        remainder *= 10
        digit = remainder // denominator
        decimal_digits.append(digit)
        remainder %= denominator
        if remainder == 0:
            break

    if n - len(str(integer_part)) <= len(decimal_digits):
        return decimal_digits[n - len(str(integer_part)) - 1]
    else:
        # This case should not be reached if n is within bounds
        return 0

def find_Nth_Digit(numerator, denominator, n):
    if denominator == 0:
        raise ValueError("Denominator cannot be zero.")
    if n <= 0:
        raise ValueError("n must be a positive integer.")

    # Perform division and extract digits
    quotient = numerator / denominator
    integer_part = int(quotient)

    if n <= len(str(integer_part)):
        # If n is within the integer part
        return int(str(integer_part)[n-1])

    # Extract decimal part
    decimal_part = quotient - integer_part

    # Generate decimal digits
    digits = []
    remainder = numerator % denominator

    for _ in range(n - len(str(integer_part)) - 1):
        remainder *= 10
        if remainder == 0:
            break
        digit = remainder // denominator
        digits.append(digit)
        remainder %= denominator

    if digits:
        return digits[-1]
    else:
        # If remainder becomes 0 before reaching n-th digit, return 0
        return 0

