def compute_Last_Digit(a, b):
    def factorial(n):
        result = 1
        for i in range(2, n + 1):
            result *= i
        return result

    def get_last_digit(n):
        return n % 10

    if a == b:
        return get_last_digit(factorial(a))
    elif a < b:
        return get_last_digit(factorial(b) // factorial(a))
    else:
        return 0

# Test
assert compute_Last_Digit(2, 4) == 2

def compute_Last_Digit(a, b):
    def factorial(n):
        result = 1
        for i in range(2, n + 1):
            result *= i
        return result

    if a > b:
        return 0

    fact_a = factorial(a)
    fact_b = factorial(b)

    last_digit = fact_b % fact_a
    return last_digit

assert compute_Last_Digit(2, 4) == 2

