def find_Max_Num(digits, count):
    if not digits or count <= 0:
        return 0

    # Sort the digits in descending order to form the largest number
    sorted_digits = sorted(digits, reverse=True)

    # Take the first 'count' digits
    result_digits = sorted_digits[:count]

    # Convert to integer
    return int("".join(map(str, result_digits)))

def find_Max_Num(digits, k):
    digits.sort(reverse=True)
    result = []
    for i in range(k):
        result.append(str(digits[i]))
    return int("".join(result))

def find_Max_Num(digits, length):
    if length > len(digits):
        raise ValueError("Length of digits must be less than or equal to the specified length.")

    digits = sorted(digits, reverse=True)

    result = []
    for _ in range(length):
        if _ == 0:
            result.append(digits[0])
        else:
            max_val = max(digits)
            result.append(max_val)

    return int("".join(map(str, result)))

# Test
assert find_Max_Num([1, 2, 3], 3) == 321

def find_Max_Num(digits, n):
    if n == 0:
        return 0
    digits = sorted(digits, reverse=True)
    result = []
    for _ in range(n):
        if _ == 0 and digits[0] == 0:
            result.append(0)
            continue
        result.append(digits[0])
        digits.pop(0)
    return int(''.join(map(str, result)))

