def bell_number(n):
    """
    Calculate the nth Bell number, which is the number of partitions of a set with n elements.
    """
    if n < 0:
        raise ValueError("Input must be a non-negative integer")

    # Create a table for Bell numbers
    # B[n][k] = number of ways to partition a set of n elements into k non-empty subsets
    B = [[0] * (n + 1) for _ in range(n + 1)]

    # Base case: B[0][0] = 1
    B[0][0] = 1

    # Fill the table using the recurrence relation:
    # B(n, k) = sum(B(n-1, j) * C(n-1, k-1)) for j from 1 to k
    # Where C(n, k) is the binomial coefficient

    for i in range(1, n + 1):
        for j in range(1, i + 1):
            B[i][j] = sum(B[i-1][k] * combinations(i-1, j-1) for k in range(1, j))

    # The nth Bell number is the sum of the nth row
    return sum(B[n])

def combinations(n, k):
    """Calculate the binomial coefficient C(n, k)."""
    if k < 0 or k > n:
        return 0
    if k == 0 or k == n:
        return 1
    if k > n // 2:
        k = n - k

    result = 1
    for i in range(k):
        result = result * (n - i) // (i + 1)
    return result

def bell_number(n):
    if n == 0:
        return 1
    if n == 1:
        return 1

    bell = [0] * (n + 1)
    bell[0] = 1

    for i in range(1, n + 1):
        for j in range(i):
            bell[i] += bell[j] * bell[i - j - 1]

    return bell[n]

