    if n < 0:
        return 0
    if n == 0:
        return 1

    bell = [0] * (n + 1)
    bell[0] = 1

    for i in range(1, n + 1):
        bell[i] = sum(bell[i - j] * comb(i - 1, j - 1) for j in range(1, i + 1))

    return bell[n]

