def count_Squares(width, height):
    if width <= 0 or height <= 0:
        return 0

    total_squares = 0

    # Count squares of size 1x1
    for i in range(1, width + 1):
        for j in range(1, height + 1):
            if i <= width and j <= height:
                total_squares += 1

    # Count squares of size 2x2
    for i in range(1, width - 1 + 1):
        for j in range(1, height - 1 + 1):
            if i <= width - 1 and j <= height - 1:
                total_squares += 1

    # Count squares of size kxk
    for k in range(1, min(width, height) + 1):
        num_positions_width = width - k + 1
        num_positions_height = height - k + 1
        total_squares += num_positions_width * num_positions_height

    return total_squares

