def count_With_Odd_SetBits(n):
    """
    Returns the number of integers between 0 and n (inclusive) 
    that have an odd number of set bits (1s in binary representation).
    """
    count = 0
    for i in range(n + 1):
        if bin(i).count('1') % 2 == 1:
            count += 1
    return count

