def is_undulating(n):
    """
    Check if the number (given as string) is undulating.
    An undulating number has digits that alternate strictly between increasing and decreasing.
    """
    if len(n) <= 1:
        return True

    for i in range(1, len(n)):
        if i % 2 == 1:  # Odd index (2nd digit onwards)
            if n[i] >= n[i-1]:
                return False
        else:  # Even index
            if n[i] <= n[i-1]:
                return False

    return True

