def find_next_palindrome(n):
    """Find the next palindrome greater than n."""
    s = str(n)
    length = len(s)

    # Try to construct a palindrome by mirroring the first half
    half = s[:length // 2]
    if length % 2 == 0:
        # Even length: mirror the first half
        candidate = half + half[::-1]
    else:
        # Odd length: mirror the first half excluding the middle digit
        candidate = half + half[-1] + half[::-1]

    # If candidate is greater than n, we found our answer
    if int(candidate) > n:
        return int(candidate)

    # If not, we need to increment the first half and try again
    # Increment the half part
    half_int = int(half)
    half_int += 1

    # Convert back to string and handle carry
    new_half = str(half_int).zfill(len(half))

    if length % 2 == 0:
        candidate = new_half + new_half[::-1]
    else:
        candidate = new_half + new_half[-1] + new_half[::-1]

    return int(candidate)

