    center = n // 2
    if n % 2 == 0:
        center = center + 1

    for row in square:
        if row[0] != row[-1]:
            return False
        for i in range(len(row) - 1):
            if row[i] != row[i + 2]:
                return False

    for i in range(n):
        if square[i][center] != square[i][center - 1]:
            return False
        if square[i][center] != square[i][center + 1]:
            return False

    for i in range(n):
        if square[i][i] != square[i][i - 1]:
            return False
        if square[i][i] != square[i][i + 1]:
            return False

    for i in range(n):
        if square[i][n - i - 1] != square[i][n - i - 2]:
            return False
        if square[i][n - i - 1] != square[i][n - i]:
            return False

    for i in range(n):
        if square[n - i - 1][center] != square[n - i - 2][center]:
            return False
        if square[n - i - 1][center] != square[n - i - 1][center + 1]:
            return False

    for i in range(n):
        if square[i][i + 1] != square[i][i + 2]:
            return False
        if square[i][i + 1] != square[i][i + 3]:
            return False

    for i in range(n):
        if square[i][i + 1] != square[i + 1][i]:
            return False
        if square[i][i + 1] != square[i + 1][i + 1]:
            return False

    return True

