from collections import Counter

def max_occurrences(lst):
    if not lst:
        return None
    counter = Counter(lst)
    max_count = 0
    max_item = None
    for item, count in counter.items():
        if count > max_count:
            max_count = count
            max_item = item
    return (max_item, max_count)
